import{_ as l,o as t,c as e,am as r}from"./chunks/framework.yzuB8YhR.js";const b=JSON.parse('{"title":"📡 协议的本质","description":"","frontmatter":{},"headers":[],"relativePath":"基础/计算机/计算机网络/初识计算机网络/协议的本质.md","filePath":"基础/计算机/计算机网络/初识计算机网络/协议的本质.md","lastUpdated":1776923458000}'),i={name:"基础/计算机/计算机网络/初识计算机网络/协议的本质.md"};function o(d,a,h,n,s,c){return t(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="📡-协议的本质" tabindex="-1">📡 协议的本质 <a class="header-anchor" href="#📡-协议的本质" aria-label="Permalink to “📡 协议的本质”">​</a></h1><h2 id="🎯-学习目标" tabindex="-1">🎯 学习目标 <a class="header-anchor" href="#🎯-学习目标" aria-label="Permalink to “🎯 学习目标”">​</a></h2><p>本节课的目标是：</p><ul><li>对<strong>计算机网络</strong>形成整体认知</li><li>理解“<strong>计算机之间如何通信</strong>”的基本原理</li></ul><hr><h2 id="🌐-一、什么是计算机网络" tabindex="-1">🌐 一、什么是计算机网络？ <a class="header-anchor" href="#🌐-一、什么是计算机网络" aria-label="Permalink to “🌐 一、什么是计算机网络？”">​</a></h2><p>计算机网络可以将<strong>原本孤立的计算机连接起来</strong>，使它们能够：</p><ul><li>互相发送数据</li><li>进行信息交换</li></ul><h3 id="基本概念" tabindex="-1">基本概念： <a class="header-anchor" href="#基本概念" aria-label="Permalink to “基本概念：”">​</a></h3><ul><li><strong>主机（Host）</strong>：接入网络的计算机</li><li><strong>发送方（Sender）</strong>：发送数据的一方</li><li><strong>接收方（Receiver）</strong>：接收数据的一方</li></ul><p>📌 同一台主机：</p><ul><li>发送时 → 发送方</li><li>接收时 → 接收方</li></ul><hr><h2 id="📶-二、数据是如何传输的" tabindex="-1">📶 二、数据是如何传输的？ <a class="header-anchor" href="#📶-二、数据是如何传输的" aria-label="Permalink to “📶 二、数据是如何传输的？”">​</a></h2><h3 id="_1️⃣-数据的本质形式" tabindex="-1">1️⃣ 数据的本质形式 <a class="header-anchor" href="#_1️⃣-数据的本质形式" aria-label="Permalink to “1️⃣ 数据的本质形式”">​</a></h3><p>计算机网络中，数据不是直接以字符传输，而是：</p><blockquote><p><strong>以“信号波形”的形式在线路中传播</strong></p></blockquote><hr><h3 id="_2️⃣-数据传输流程" tabindex="-1">2️⃣ 数据传输流程 <a class="header-anchor" href="#_2️⃣-数据传输流程" aria-label="Permalink to “2️⃣ 数据传输流程”">​</a></h3><p>原始数据 → 编码 → 二进制（0/1） → 信号波 → 传输 → 接收 → 解码</p><hr><h3 id="_3️⃣-为什么要编码" tabindex="-1">3️⃣ 为什么要编码？ <a class="header-anchor" href="#_3️⃣-为什么要编码" aria-label="Permalink to “3️⃣ 为什么要编码？”">​</a></h3><p>计算机只能识别：</p><blockquote><p><strong>二进制（0 和 1）</strong></p></blockquote><p>因此需要通过<strong>编码方式</strong>将数据转换：</p><table tabindex="0"><thead><tr><th>数据类型</th><th>编码方式</th></tr></thead><tbody><tr><td>文本</td><td>ASCII / GBK / UTF-8</td></tr><tr><td>图片</td><td>图像编码</td></tr><tr><td>音视频</td><td>音视频编码</td></tr></tbody></table><hr><h2 id="⚠️-三、仅传输数据会出现的问题" tabindex="-1">⚠️ 三、仅传输数据会出现的问题 <a class="header-anchor" href="#⚠️-三、仅传输数据会出现的问题" aria-label="Permalink to “⚠️ 三、仅传输数据会出现的问题”">​</a></h2><h3 id="❌-问题1-无法确定数据边界" tabindex="-1">❌ 问题1：无法确定数据边界 <a class="header-anchor" href="#❌-问题1-无法确定数据边界" aria-label="Permalink to “❌ 问题1：无法确定数据边界”">​</a></h3><p>例如发送 <code>&quot;Hi&quot;</code>：</p><p>Hi → 编码 → 01001000 01101001</p><p>接收方问题：</p><ul><li>不知道数据长度</li><li>不知道从哪里开始、哪里结束</li></ul><p>👉 如果多个数据混在一起：</p><p>0101 0101 1111 0000 ...</p><p>无法区分不同数据！</p><hr><h3 id="❌-问题2-无法识别数据格式" tabindex="-1">❌ 问题2：无法识别数据格式 <a class="header-anchor" href="#❌-问题2-无法识别数据格式" aria-label="Permalink to “❌ 问题2：无法识别数据格式”">​</a></h3><p>例如：</p><ul><li>普通文本 <code>&quot;Hi&quot;</code></li><li>JSON 数据 <code>{ &quot;name&quot;: &quot;Tom&quot; }</code></li></ul><p>接收方：</p><ul><li>不知道数据类型</li><li>不知道该用什么方式解析</li></ul><hr><h2 id="🧠-四、解决方案-添加-额外信息" tabindex="-1">🧠 四、解决方案：添加“额外信息” <a class="header-anchor" href="#🧠-四、解决方案-添加-额外信息" aria-label="Permalink to “🧠 四、解决方案：添加“额外信息””">​</a></h2><h3 id="✔️-思路" tabindex="-1">✔️ 思路 <a class="header-anchor" href="#✔️-思路" aria-label="Permalink to “✔️ 思路”">​</a></h3><p>除了发送数据本身，还需要发送：</p><blockquote><p><strong>描述数据的信息（元数据）</strong></p></blockquote><hr><h3 id="📦-数据结构" tabindex="-1">📦 数据结构 <a class="header-anchor" href="#📦-数据结构" aria-label="Permalink to “📦 数据结构”">​</a></h3><p>+------------+----------------+ | Header | Body | +------------+----------------+</p><h4 id="🔹-header-首部" tabindex="-1">🔹 Header（首部） <a class="header-anchor" href="#🔹-header-首部" aria-label="Permalink to “🔹 Header（首部）”">​</a></h4><p>包含：</p><ul><li>数据长度（Content-Length）</li><li>数据类型（Content-Type）</li><li>其他控制信息</li></ul><h4 id="🔹-body-主体-payload" tabindex="-1">🔹 Body（主体 / Payload） <a class="header-anchor" href="#🔹-body-主体-payload" aria-label="Permalink to “🔹 Body（主体 / Payload）”">​</a></h4><ul><li>实际数据内容</li></ul><hr><h2 id="🤝-五、核心-协议-protocol" tabindex="-1">🤝 五、核心：协议（Protocol） <a class="header-anchor" href="#🤝-五、核心-协议-protocol" aria-label="Permalink to “🤝 五、核心：协议（Protocol）”">​</a></h2><h3 id="📌-定义" tabindex="-1">📌 定义 <a class="header-anchor" href="#📌-定义" aria-label="Permalink to “📌 定义”">​</a></h3><blockquote><p><strong>协议 = 通信双方共同遵守的规则（约定）</strong></p></blockquote><hr><h3 id="🧩-协议解决的问题" tabindex="-1">🧩 协议解决的问题 <a class="header-anchor" href="#🧩-协议解决的问题" aria-label="Permalink to “🧩 协议解决的问题”">​</a></h3><p>协议规定：</p><table tabindex="0"><thead><tr><th>内容</th><th>说明</th></tr></thead><tbody><tr><td>数据格式</td><td>Header 怎么写</td></tr><tr><td>字段含义</td><td>length 表示什么</td></tr><tr><td>编码方式</td><td>如何解析数据</td></tr><tr><td>处理方式</td><td>收到数据后如何处理</td></tr></tbody></table><hr><h3 id="⚠️-关键点" tabindex="-1">⚠️ 关键点 <a class="header-anchor" href="#⚠️-关键点" aria-label="Permalink to “⚠️ 关键点”">​</a></h3><p>✔ 协议的本质不是格式，而是：</p><blockquote><p><strong>双方必须遵守同一套规则</strong></p></blockquote><p>✔ 必须满足：</p><ul><li>有协议 ✅</li><li>双方使用<strong>同一个协议</strong> ✅</li></ul><p>否则：</p><blockquote><p>❌ 无法通信</p></blockquote><hr><h2 id="💻-六、协议的实现" tabindex="-1">💻 六、协议的实现 <a class="header-anchor" href="#💻-六、协议的实现" aria-label="Permalink to “💻 六、协议的实现”">​</a></h2><p>协议不是“口头约定”，而是：</p><blockquote><p><strong>通过代码实现的规则</strong></p></blockquote><p>例如：</p><h3 id="发送端" tabindex="-1">发送端： <a class="header-anchor" href="#发送端" aria-label="Permalink to “发送端：”">​</a></h3><ul><li>按协议构造 Header</li><li>拼接数据</li><li>发送</li></ul><h3 id="接收端" tabindex="-1">接收端： <a class="header-anchor" href="#接收端" aria-label="Permalink to “接收端：”">​</a></h3><ul><li>解析 Header</li><li>读取数据长度</li><li>按类型处理数据</li></ul><hr><h2 id="🌍-七、常见网络协议" tabindex="-1">🌍 七、常见网络协议 <a class="header-anchor" href="#🌍-七、常见网络协议" aria-label="Permalink to “🌍 七、常见网络协议”">​</a></h2><table tabindex="0"><thead><tr><th>协议</th><th>用途</th></tr></thead><tbody><tr><td>HTTP</td><td>超文本传输（网页）</td></tr><tr><td>FTP</td><td>文件传输</td></tr><tr><td>SMTP</td><td>邮件发送</td></tr><tr><td>POP3 / IMAP</td><td>邮件接收</td></tr></tbody></table><p>📌 特点：</p><ul><li>协议很多</li><li>各自有不同规则</li><li>针对不同场景优化</li></ul><hr><h2 id="📦-八、协议数据单元-pdu" tabindex="-1">📦 八、协议数据单元（PDU） <a class="header-anchor" href="#📦-八、协议数据单元-pdu" aria-label="Permalink to “📦 八、协议数据单元（PDU）”">​</a></h2><h3 id="定义" tabindex="-1">定义： <a class="header-anchor" href="#定义" aria-label="Permalink to “定义：”">​</a></h3><blockquote><p><strong>协议数据单元（Protocol Data Unit） = Header + Body</strong></p></blockquote><p>PDU = Header + Payload</p><hr><h2 id="🧾-九、总结" tabindex="-1">🧾 九、总结 <a class="header-anchor" href="#🧾-九、总结" aria-label="Permalink to “🧾 九、总结”">​</a></h2><h3 id="🔑-核心要点" tabindex="-1">🔑 核心要点 <a class="header-anchor" href="#🔑-核心要点" aria-label="Permalink to “🔑 核心要点”">​</a></h3><ol><li><p><strong>网络的本质</strong></p><ul><li>让计算机之间可以通信</li></ul></li><li><p><strong>数据传输过程</strong></p><ul><li>数据 → 二进制 → 信号 → 传输 → 还原</li></ul></li><li><p><strong>关键问题</strong></p><ul><li>数据边界不清</li><li>数据格式不明</li></ul></li><li><p><strong>解决方案</strong></p><ul><li>添加 Header（额外信息）</li></ul></li><li><p><strong>最核心概念</strong></p><blockquote><p>⭐ 协议 = 通信的基础</p></blockquote></li><li><p><strong>通信成立条件</strong></p><ul><li>双方必须使用<strong>相同协议</strong></li></ul></li></ol><hr><h2 id="🚀-一句话理解" tabindex="-1">🚀 一句话理解 <a class="header-anchor" href="#🚀-一句话理解" aria-label="Permalink to “🚀 一句话理解”">​</a></h2><blockquote><p><strong>计算机网络通信 = 数据 + 额外信息（Header） + 双方遵守的协议</strong></p></blockquote>',97)])])}const u=l(i,[["render",o]]);export{b as __pageData,u as default};
